import{_ as e,o as l,c as d,a4 as a}from"./chunks/framework._in6GHBg.js";const h=JSON.parse('{"title":"物理模型速查总卡","description":"","frontmatter":{},"headers":[],"relativePath":"physics/quickref.md","filePath":"physics/quickref.md"}'),n={name:"physics/quickref.md"};function r(s,t,i,g,x,y){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="物理模型速查总卡" tabindex="-1">物理模型速查总卡 <a class="header-anchor" href="#物理模型速查总卡" aria-label="Permalink to &quot;物理模型速查总卡&quot;">​</a></h1><p><strong>高中物理26个核心模型 · 一页纸速查</strong></p><hr><h2 id="高一上-运动学-力学-15个模型" tabindex="-1">高一上：运动学+力学（15个模型） <a class="header-anchor" href="#高一上-运动学-力学-15个模型" aria-label="Permalink to &quot;高一上：运动学+力学（15个模型）&quot;">​</a></h2><h3 id="运动学-m01-m05" tabindex="-1">运动学 M01-M05 <a class="header-anchor" href="#运动学-m01-m05" aria-label="Permalink to &quot;运动学 M01-M05&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>M01匀变速</strong></td><td style="text-align:left;">v=v₀+at, x=v₀t+½at²</td><td style="text-align:left;">加速度恒定</td><td style="text-align:left;">矢量方向、刹车陷阱</td></tr><tr><td style="text-align:center;"><strong>M02自由落体</strong></td><td style="text-align:left;">v=gt, h=½gt²</td><td style="text-align:left;">v₀=0, a=g</td><td style="text-align:left;">方向选取</td></tr><tr><td style="text-align:center;"><strong>M03竖直上抛</strong></td><td style="text-align:left;">对称性、分段处理</td><td style="text-align:left;">最高点v=0</td><td style="text-align:left;">时间对称性</td></tr><tr><td style="text-align:center;"><strong>M04追及相遇</strong></td><td style="text-align:left;">位移相等列等式</td><td style="text-align:left;">速度相等是临界</td><td style="text-align:left;">相遇次数判断</td></tr><tr><td style="text-align:center;"><strong>M05合成与分解</strong></td><td style="text-align:left;">独立性、等时性</td><td style="text-align:left;">分运动互不干扰</td><td style="text-align:left;">时间相同</td></tr></tbody></table><h3 id="力学基础-m06-m10" tabindex="-1">力学基础 M06-M10 <a class="header-anchor" href="#力学基础-m06-m10" aria-label="Permalink to &quot;力学基础 M06-M10&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式/方法</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>M06弹力</strong></td><td style="text-align:left;">F=kx（胡克定律）</td><td style="text-align:left;">弹簧原长/形变量</td><td style="text-align:left;">形变量不是长度</td></tr><tr><td style="text-align:center;"><strong>M07摩擦力</strong></td><td style="text-align:left;">f=μN</td><td style="text-align:left;">相对运动方向</td><td style="text-align:left;">静摩擦vs滑动摩擦</td></tr><tr><td style="text-align:center;"><strong>M08力的合成</strong></td><td style="text-align:left;">平行四边形法则</td><td style="text-align:left;">合力范围</td><td style="text-align:left;">分力与合力关系</td></tr><tr><td style="text-align:center;"><strong>M09共点力平衡</strong></td><td style="text-align:left;">ΣF=0</td><td style="text-align:left;">正交分解</td><td style="text-align:left;">漏力分析</td></tr><tr><td style="text-align:center;"><strong>M10牛顿第一定律</strong></td><td style="text-align:left;">惯性、理想实验</td><td style="text-align:left;">力改变运动状态</td><td style="text-align:left;">惯性大小</td></tr></tbody></table><h3 id="牛顿定律进阶-m11-m15" tabindex="-1">牛顿定律进阶 M11-M15 <a class="header-anchor" href="#牛顿定律进阶-m11-m15" aria-label="Permalink to &quot;牛顿定律进阶 M11-M15&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心思路</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>M11牛顿第二定律</strong></td><td style="text-align:left;">F=ma</td><td style="text-align:left;">合外力与加速度</td><td style="text-align:left;">瞬时性、矢量性</td></tr><tr><td style="text-align:center;"><strong>M12牛顿第三定律</strong></td><td style="text-align:left;">F₁₂=-F₂₁</td><td style="text-align:left;">作用力与反作用力</td><td style="text-align:left;">与平衡力区分</td></tr><tr><td style="text-align:center;"><strong>M13连接体问题</strong></td><td style="text-align:left;">先整体后隔离</td><td style="text-align:left;">加速度相同</td><td style="text-align:left;">内力分析</td></tr><tr><td style="text-align:center;"><strong>M14传送带问题</strong></td><td style="text-align:left;">分段：加速+共速</td><td style="text-align:left;">找共速点</td><td style="text-align:left;">摩擦力突变</td></tr><tr><td style="text-align:center;"><strong>M15板块问题</strong></td><td style="text-align:left;">分别分析→相对位移</td><td style="text-align:left;">是否相对滑动</td><td style="text-align:left;">摩擦力做功</td></tr></tbody></table><hr><h2 id="高一下-曲线运动-电磁学基础-2个模型" tabindex="-1">高一下：曲线运动+电磁学基础（2个模型） <a class="header-anchor" href="#高一下-曲线运动-电磁学基础-2个模型" aria-label="Permalink to &quot;高一下：曲线运动+电磁学基础（2个模型）&quot;">​</a></h2><h3 id="曲线运动-m16-m17" tabindex="-1">曲线运动 M16-M17 <a class="header-anchor" href="#曲线运动-m16-m17" aria-label="Permalink to &quot;曲线运动 M16-M17&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>M16曲线运动</strong></td><td style="text-align:left;">向心力F=mv²/r</td><td style="text-align:left;">切向/法向分解</td><td style="text-align:left;">向心力是效果力</td></tr><tr><td style="text-align:center;"><strong>M17平抛运动</strong></td><td style="text-align:left;">x=v₀t, y=½gt²</td><td style="text-align:left;">水平匀速+竖直自由落体</td><td style="text-align:left;">tanθ=2tanα</td></tr></tbody></table><hr><h2 id="高二-电磁学-9个模型" tabindex="-1">高二：电磁学（9个模型） <a class="header-anchor" href="#高二-电磁学-9个模型" aria-label="Permalink to &quot;高二：电磁学（9个模型）&quot;">​</a></h2><h3 id="静电学-m18-m21" tabindex="-1">静电学 M18-M21 <a class="header-anchor" href="#静电学-m18-m21" aria-label="Permalink to &quot;静电学 M18-M21&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>M18库仑定律</strong></td><td style="text-align:left;">F=kQ₁Q₂/r²</td><td style="text-align:left;">点电荷、距离</td><td style="text-align:left;">方向判断</td></tr><tr><td style="text-align:center;"><strong>M19电场强度</strong></td><td style="text-align:left;">E=F/q, E=kQ/r²</td><td style="text-align:left;">场强方向</td><td style="text-align:left;">矢量叠加</td></tr><tr><td style="text-align:center;"><strong>M20电势与电势能</strong></td><td style="text-align:left;">Ep=qφ, W=-ΔEp</td><td style="text-align:left;">电势零点选取</td><td style="text-align:left;">正负电荷</td></tr><tr><td style="text-align:center;"><strong>M21电容器</strong></td><td style="text-align:left;">C=Q/U, C=εS/4πkd</td><td style="text-align:left;">与电源连接/断开</td><td style="text-align:left;">场强不变</td></tr></tbody></table><h3 id="电路-m22-m23" tabindex="-1">电路 M22-M23 <a class="header-anchor" href="#电路-m22-m23" aria-label="Permalink to &quot;电路 M22-M23&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>M22欧姆定律</strong></td><td style="text-align:left;">I=U/R</td><td style="text-align:left;">伏安特性曲线</td><td style="text-align:left;">非纯电阻电路</td></tr><tr><td style="text-align:center;"><strong>M23闭合电路欧姆定律</strong></td><td style="text-align:left;">I=ε/(R+r)</td><td style="text-align:left;">路端电压变化</td><td style="text-align:left;">短路/断路分析</td></tr></tbody></table><h3 id="磁学-m24-m26" tabindex="-1">磁学 M24-M26 <a class="header-anchor" href="#磁学-m24-m26" aria-label="Permalink to &quot;磁学 M24-M26&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>M24安培力</strong></td><td style="text-align:left;">F=BILsinθ</td><td style="text-align:left;">左手定则</td><td style="text-align:left;">有效长度</td></tr><tr><td style="text-align:center;"><strong>M25洛伦兹力</strong></td><td style="text-align:left;">f=qvBsinθ</td><td style="text-align:left;">不做功、改变方向</td><td style="text-align:left;">圆周运动半径</td></tr><tr><td style="text-align:center;"><strong>M26电磁感应</strong></td><td style="text-align:left;">ε=BLv, ε=nΔΦ/Δt</td><td style="text-align:left;">磁通量变化</td><td style="text-align:left;">楞次定律方向</td></tr><tr><td style="text-align:center;"><strong>14圆锥摆</strong></td><td style="text-align:left;">tanθ=v²/rg</td><td style="text-align:left;">水平/竖直分解</td><td style="text-align:left;">几何关系</td></tr><tr><td style="text-align:center;"><strong>15天体</strong></td><td style="text-align:left;">GMm/r²=mv²/r, GM=gR²</td><td style="text-align:left;">万有引力提供向心力</td><td style="text-align:left;">轨道半径vs高度</td></tr></tbody></table><h3 id="能量动量-16-20" tabindex="-1">能量动量（16-20） <a class="header-anchor" href="#能量动量-16-20" aria-label="Permalink to &quot;能量动量（16-20）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>16动能定理</strong></td><td style="text-align:left;">W合=ΔEk</td><td style="text-align:left;">只看初末，不看过程</td><td style="text-align:left;">功的正负</td></tr><tr><td style="text-align:center;"><strong>17机械能守恒</strong></td><td style="text-align:left;">Ek₁+Ep₁=Ek₂+Ep₂</td><td style="text-align:left;">只有重力/弹力做功</td><td style="text-align:left;">条件判断</td></tr><tr><td style="text-align:center;"><strong>18功能关系</strong></td><td style="text-align:left;">Wf=-Q, W电=-ΔEp</td><td style="text-align:left;">能量转化方向</td><td style="text-align:left;">摩擦力做功</td></tr><tr><td style="text-align:center;"><strong>19动量守恒</strong></td><td style="text-align:left;">m₁v₁+m₂v₂=m₁v₁&#39;+m₂v₂&#39;</td><td style="text-align:left;">系统不受外力</td><td style="text-align:left;">矢量性</td></tr><tr><td style="text-align:center;"><strong>20能+动</strong></td><td style="text-align:left;">动量守恒+能量守恒</td><td style="text-align:left;">完全弹性碰撞</td><td style="text-align:left;">联立方程</td></tr></tbody></table><hr><h2 id="高二-电磁学-5个模型" tabindex="-1">高二：电磁学（5个模型） <a class="header-anchor" href="#高二-电磁学-5个模型" aria-label="Permalink to &quot;高二：电磁学（5个模型）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:left;">核心公式</th><th style="text-align:left;">关键判断点</th><th style="text-align:left;">易错点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>21电场粒子</strong></td><td style="text-align:left;">a=qU/md, y=qUL²/2mdv₀²</td><td style="text-align:left;">类平抛</td><td style="text-align:left;">偏转距离公式</td></tr><tr><td style="text-align:center;"><strong>22磁场粒子</strong></td><td style="text-align:left;">r=mv/qB, T=2πm/qB</td><td style="text-align:left;">找圆心定半径</td><td style="text-align:left;">几何关系</td></tr><tr><td style="text-align:center;"><strong>23复合场</strong></td><td style="text-align:left;">分段分析</td><td style="text-align:left;">找衔接点（速度）</td><td style="text-align:left;">洛伦兹力不做功</td></tr><tr><td style="text-align:center;"><strong>24单杆切割</strong></td><td style="text-align:left;">ε=BLv, I=BLv/R, F=BIL</td><td style="text-align:left;">安培力阻碍运动</td><td style="text-align:left;">能量转化</td></tr><tr><td style="text-align:center;"><strong>25双杆切割</strong></td><td style="text-align:left;">动量守恒+能量守恒</td><td style="text-align:left;">等效电路分析</td><td style="text-align:left;">相对速度</td></tr></tbody></table><hr><h2 id="快速索引" tabindex="-1">快速索引 <a class="header-anchor" href="#快速索引" aria-label="Permalink to &quot;快速索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:center;">模型编号</th><th style="text-align:left;">学期</th></tr></thead><tbody><tr><td style="text-align:left;">运动学</td><td style="text-align:center;">01-04</td><td style="text-align:left;">高一上（9-10月）</td></tr><tr><td style="text-align:left;">力学平衡</td><td style="text-align:center;">05-07</td><td style="text-align:left;">高一上（10-11月）</td></tr><tr><td style="text-align:left;">牛顿定律</td><td style="text-align:center;">08-12</td><td style="text-align:left;">高一上（11月-1月）</td></tr><tr><td style="text-align:left;">曲线运动</td><td style="text-align:center;">13-15</td><td style="text-align:left;">高一下（2-4月）</td></tr><tr><td style="text-align:left;">能量动量</td><td style="text-align:center;">16-20</td><td style="text-align:left;">高一下（4-7月）</td></tr><tr><td style="text-align:left;">电磁学</td><td style="text-align:center;">21-25</td><td style="text-align:left;">高二全年</td></tr></tbody></table><hr><h2 id="方法选择速查" tabindex="-1">方法选择速查 <a class="header-anchor" href="#方法选择速查" aria-label="Permalink to &quot;方法选择速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">题目特征</th><th style="text-align:left;">首选方法</th><th style="text-align:left;">次选方法</th></tr></thead><tbody><tr><td style="text-align:left;">已知力，求运动</td><td style="text-align:left;">牛顿定律</td><td style="text-align:left;">能量法</td></tr><tr><td style="text-align:left;">已知运动，求力</td><td style="text-align:left;">牛顿定律</td><td style="text-align:left;">能量法</td></tr><tr><td style="text-align:left;">有位移、速度，无时间</td><td style="text-align:left;"><strong>动能定理</strong></td><td style="text-align:left;">能量守恒</td></tr><tr><td style="text-align:left;">只有重力/弹力做功</td><td style="text-align:left;"><strong>能量守恒</strong></td><td style="text-align:left;">动能定理</td></tr><tr><td style="text-align:left;">碰撞、爆炸、反冲</td><td style="text-align:left;"><strong>动量守恒</strong></td><td style="text-align:left;">能量法</td></tr><tr><td style="text-align:left;">多过程复杂</td><td style="text-align:left;"><strong>能量法</strong></td><td style="text-align:left;">分段牛顿</td></tr><tr><td style="text-align:left;">瞬时作用</td><td style="text-align:left;"><strong>动量定理</strong></td><td style="text-align:left;">—</td></tr></tbody></table><hr><h2 id="单位换算速查" tabindex="-1">单位换算速查 <a class="header-anchor" href="#单位换算速查" aria-label="Permalink to &quot;单位换算速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">物理量</th><th style="text-align:left;">常用单位</th><th style="text-align:left;">换算关系</th></tr></thead><tbody><tr><td style="text-align:left;">长度</td><td style="text-align:left;">cm → m</td><td style="text-align:left;">×10⁻²</td></tr><tr><td style="text-align:left;">质量</td><td style="text-align:left;">g → kg</td><td style="text-align:left;">×10⁻³</td></tr><tr><td style="text-align:left;">速度</td><td style="text-align:left;">km/h → m/s</td><td style="text-align:left;">÷3.6</td></tr><tr><td style="text-align:left;">面积</td><td style="text-align:left;">cm² → m²</td><td style="text-align:left;">×10⁻⁴</td></tr><tr><td style="text-align:left;">体积</td><td style="text-align:left;">L → m³</td><td style="text-align:left;">×10⁻³</td></tr></tbody></table><hr><h2 id="检查清单-每道题必做" tabindex="-1">检查清单（每道题必做） <a class="header-anchor" href="#检查清单-每道题必做" aria-label="Permalink to &quot;检查清单（每道题必做）&quot;">​</a></h2><ul><li>[ ] <strong>单位统一</strong>：所有量都用国际单位制</li><li>[ ] <strong>方向明确</strong>：矢量规定正方向</li><li>[ ] <strong>过程完整</strong>：分段问题的转折点</li><li>[ ] <strong>答案合理</strong>：数量级估算</li></ul><hr><p><em>文档编号</em>: TS-000-PHYS-速查总卡<br><em>版本</em>: V1.0<br><em>用途</em>: 做题卡壳时快速查阅，考前快速复习<br><em>建议</em>: 打印成A3或缩印成A4便携</p>',41)])])}const o=e(n,[["render",r]]);export{h as __pageData,o as default};
